const morgan = require('morgan');
const logger = require('../utils/logger');

// Define a standardized morgan format focusing on Method, Route (URL), Status, and Time
const morganFormat = ':method :url :status - :response-time ms';

/**
 * Pipes API Request logs generated by Express completely into our central Winston logger.
 * This guarantees that Request Logs sit side-by-side perfectly with System Error Logs.
 */
const httpLogger = morgan(morganFormat, {
  stream: {
    // Write strips newline auto-added by morgan, forwarding strictly raw string payload to Winston
    write: (message) => {
      logger.info(message.trim());
    },
  },
});

module.exports = httpLogger;
